// // This module implements a custom logic gate where the output X is activated when either A1 or A2 is low, and both B1 and B2 are low, regardless of the state of C1.
module top_module(
    input A1,
    input A2,
    input B1,
    input B2,
    input C1,
    output reg X
);// Voltage supply signals
    supply1 VPWR;
    supply0 VGND;

    always @(*) begin
        X = (A1 & A2 & (B1 | B2) & ~C1);
    end

endmodule
